UPDATE order_tickets
SET partner_order_code = #{tno}
WHERE id = (
    SELECT id
    FROM order_tickets
    WHERE order_item_id = #{orderItemId}
      AND partner_order_code IS NULL
    ORDER BY created_at
    LIMIT 1
    )

UPDATE order_tickets
SET partner_order_number = #{trno}
WHERE id = (
    SELECT id
    FROM order_tickets
    WHERE order_item_id = #{orderItemId}
      AND partner_order_number IS NULL
    ORDER BY created_at
    LIMIT 1
    )
